// PinchToMergeTwoCards.tsx
import React from 'react';
import {StyleSheet, Text} from 'react-native';
import {Gesture, GestureDetector} from 'react-native-gesture-handler';
import Animated, {useAnimatedStyle, useSharedValue, withSpring} from 'react-native-reanimated';
export function PinchToMergeTwoCards() {
  const x = useSharedValue(0); const y = useSharedValue(0); const scale = useSharedValue(1);
  const gesture = Gesture.Pinch()
    .onUpdate((event: any) => { if ('translationX' in event) { x.value = event.translationX; y.value = event.translationY; } if ('scale' in event) scale.value = Math.max(0.82, Math.min(1.8, event.scale)); })
    .onEnd(() => { x.value = withSpring(0); y.value = withSpring(0); scale.value = withSpring(1); });
  const style = useAnimatedStyle(() => ({transform: [{translateX: x.value}, {translateY: y.value}, {scale: scale.value}]}));
  return <GestureDetector gesture={gesture}><Animated.View style={[styles.surface, style]} accessibilityRole="adjustable" accessibilityLabel="Pinch to merge two cards" accessibilityActions={[{name: 'activate', label: 'Perform action'}]}><Text style={styles.title}>Pinch to merge two cards</Text></Animated.View></GestureDetector>;
}
const styles = StyleSheet.create({surface: {minHeight: 132, borderRadius: 18, backgroundColor: '#f8fafc', borderWidth: 1, borderColor: '#cbd5e1', alignItems: 'center', justifyContent: 'center', padding: 18}, title: {fontSize: 16, fontWeight: '700', color: '#0f172a', textAlign: 'center'}});

