// ImageOverlayDrawingWithMultipleLayers.tsx
import React, {useCallback, useMemo, useState} from 'react';
import {StyleSheet, View, Text, Pressable, Image, FlatList} from 'react-native';
import * as ImagePicker from 'expo-image-picker';

type UploadItem = {id: string; uri: string; progress: number; status: 'queued' | 'uploading' | 'done' | 'failed'};
export function ImageOverlayDrawingWithMultipleLayers({upload}: {upload: (item: UploadItem, onProgress: (n: number) => void) => Promise<void>}) {
  const [items, setItems] = useState<UploadItem[]>([]);
  const pendingCount = useMemo(() => items.filter(i => i.status !== 'done').length, [items]);
  const pick = useCallback(async () => {
    const result = await ImagePicker.launchImageLibraryAsync({allowsMultipleSelection: true, quality: 0.82, mediaTypes: ImagePicker.MediaTypeOptions.All});
    if (result.canceled) return;
    const next = result.assets.map((asset) => ({id: asset.assetId ?? asset.uri, uri: asset.uri, progress: 0, status: 'queued' as const}));
    setItems((current) => [...current, ...next]);
    for (const item of next) {
      setItems((current) => current.map(i => i.id === item.id ? {...i, status: 'uploading'} : i));
      try { await upload(item, (progress) => setItems((current) => current.map(i => i.id === item.id ? {...i, progress} : i))); setItems((current) => current.map(i => i.id === item.id ? {...i, status: 'done', progress: 1} : i)); }
      catch { setItems((current) => current.map(i => i.id === item.id ? {...i, status: 'failed'} : i)); }
    }
  }, [upload]);
  return <View style={styles.wrap} accessibilityLabel="Image overlay drawing with multiple layers"><Pressable onPress={pick} accessibilityRole="button" accessibilityLabel="Choose media" style={styles.pick}><Text style={styles.pickText}>Add media</Text></Pressable><Text accessibilityLiveRegion="polite">{pendingCount} pending</Text><FlatList data={items} keyExtractor={(item) => item.id} numColumns={3} renderItem={({item}) => <View style={styles.tile}><Image source={{uri: item.uri}} style={styles.image} /><View style={[styles.progress, {width: `${Math.round(item.progress * 100)}%`}]} /><Text style={styles.badge}>{item.status}</Text></View>} /></View>;
}
const styles = StyleSheet.create({wrap: {gap: 12}, pick: {minHeight: 44, borderRadius: 12, alignItems: 'center', justifyContent: 'center', backgroundColor: '#111827'}, pickText: {color: 'white', fontWeight: '700'}, tile: {width: '33.33%', aspectRatio: 1, padding: 4}, image: {flex: 1, borderRadius: 12, backgroundColor: '#e5e7eb'}, progress: {position: 'absolute', left: 4, bottom: 4, height: 3, backgroundColor: '#22c55e'}, badge: {position: 'absolute', right: 8, bottom: 8, color: 'white', backgroundColor: 'rgba(0,0,0,0.55)', paddingHorizontal: 6, borderRadius: 8, overflow: 'hidden'}});

